select bat.article_id as articleId, bt.id, bt.name, bt.description, bt.color, bt.icon, bt.create_time as createTime, bt.update_time as updateTime, bt.del_flag as delFlag from blog_article_tag bat inner join blog_tag bt on bat.tag_id = bt.id where bat.article_id in
#{articleId}
and bt.del_flag = 0 order by bat.article_id, bt.create_time desc

